import os
import json
import logging
from typing import Any, Dict, List, Optional

import boto3
from botocore.exceptions import ClientError

logger = logging.getLogger()
logger.setLevel(logging.INFO)

s3 = boto3.client("s3")
sns = boto3.client("sns")

OUTPUT_BUCKET = os.environ.get("OUTPUT_BUCKET", "")
SNS_TOPIC_ARN = os.environ.get("SNS_TOPIC_ARN", "")
PROCESSED_PREFIX = os.environ.get("PROCESSED_PREFIX", "processed/")
FAILED_PREFIX = os.environ.get("FAILED_PREFIX", "failed/")


def _safe_key_name(key: str) -> str:
    return key.replace("/", "_").replace("\\", "_")


def _get_object_bytes(bucket: str, key: str) -> bytes:
    response = s3.get_object(Bucket=bucket, Key=key)
    return response["Body"].read()


def _write_result(bucket: str, key: str, payload: Dict[str, Any]) -> None:
    s3.put_object(
        Bucket=bucket,
        Key=key,
        Body=json.dumps(payload, default=str).encode("utf-8"),
        ContentType="application/json",
    )


def _publish_notification(subject: str, message: str) -> None:
    if not SNS_TOPIC_ARN:
        logger.info("SNS_TOPIC_ARN not set; skipping notification")
        return
    sns.publish(
        TopicArn=SNS_TOPIC_ARN,
        Subject=subject[:100],
        Message=message,
    )


def process_image(bucket: str, key: str) -> Dict[str, Any]:
    image_bytes = _get_object_bytes(bucket, key)
    result = {
        "source_bucket": bucket,
        "source_key": key,
        "size_bytes": len(image_bytes),
        "status": "processed",
    }

    output_bucket = OUTPUT_BUCKET or bucket
    output_key = f"{PROCESSED_PREFIX}{_safe_key_name(key)}.json"
    _write_result(output_bucket, output_key, result)

    return {
        "output_bucket": output_bucket,
        "output_key": output_key,
        "result": result,
    }


def handle_failure(bucket: str, key: str, error: Exception) -> Dict[str, Any]:
    output_bucket = OUTPUT_BUCKET or bucket
    failure_payload = {
        "source_bucket": bucket,
        "source_key": key,
        "status": "failed",
        "error": str(error),
    }
    output_key = f"{FAILED_PREFIX}{_safe_key_name(key)}.json"
    _write_result(output_bucket, output_key, failure_payload)
    return {
        "output_bucket": output_bucket,
        "output_key": output_key,
        "result": failure_payload,
    }


def lambda_handler(event: Dict[str, Any], context: Any) -> Dict[str, Any]:
    logger.info("Received event: %s", json.dumps(event))

    records: List[Dict[str, Any]] = event.get("Records", [])
    processed: List[Dict[str, Any]] = []
    failures: List[Dict[str, Any]] = []

    for record in records:
        try:
            s3_info = record["s3"]
            bucket = s3_info["bucket"]["name"]
            key = s3_info["object"]["key"]

            logger.info("Processing image from s3://%s/%s", bucket, key)
            result = process_image(bucket, key)
            processed.append(result)

            _publish_notification(
                subject="Image processed",
                message=json.dumps(
                    {
                        "message": "Image processed successfully",
                        "source_bucket": bucket,
                        "source_key": key,
                        "output_bucket": result["output_bucket"],
                        "output_key": result["output_key"],
                    }
                ),
            )

            logger.info("Processed image: %s", json.dumps(result))
        except Exception as exc:
            logger.exception("Failed to process record")
            try:
                bucket = record.get("s3", {}).get("bucket", {}).get("name", "")
                key = record.get("s3", {}).get("object", {}).get("key", "")
                failure_result = handle_failure(bucket, key, exc)
                failures.append(failure_result)
            except Exception:
                logger.exception("Failed to write failure record")

            _publish_notification(
                subject="Image processing failed",
                message=json.dumps(
                    {
                        "message": "Image processing failed",
                        "error": str(exc),
                        "record": record,
                    },
                    default=str,
                ),
            )

    response = {
        "statusCode": 200,
        "processed_count": len(processed),
        "failure_count": len(failures),
        "processed": processed,
        "failures": failures,
    }

    logger.info("Lambda response: %s", json.dumps(response, default=str))
    return response


